// Function to validate image tags
function validateImageTags(tags) {
  let validatedTags = [];
  for (let i = 0; i < tags.length; i++) {
    let tag = tags[i];
    if (tag.includes('alt')) {
      validatedTags.push(tag);
    } else {
      validatedTags.push('Error: Image tag without 'alt' attribute at index ' + i);
    }
  }
  return validatedTags;
}

