// Solution
function validateImageTags(tags) {
  let validatedTags = [];
  for (let tag of tags) {
    if (tag.includes('alt')) {
      validatedTags.push(tag);
    } else {
      validatedTags.push('Error: Image tag without 'alt' attribute');
    }
  }
  return validatedTags;
}

solutions.python:
class Solution:
  def validateImageTags(self, tags) -> list:
    validated_tags = []
    for tag in tags:
      if 'alt' in tag:
        validated_tags.append(tag)
      else:
        validated_tags.append('Error: Image tag without 'alt' attribute')
    return validated_tags
